          succeeded++;
        } catch (err) {
          const msg = err instanceof Error ? err.message : String(err);
          failed.push({ action, error: msg });
          logger.fail(label, msg);
        }
        break;
      }
      default: {
        const _: never = action;
        throw new Error(`Unhandled deploy action kind: ${JSON.stringify(_)}`);
      }
    }
  }
```

No other lines in `deploy.ts` change. The internal functions `executeDeployAction`, `createDeployTarget`, `backupExisting`, etc. all accept `DeployAction` (which now resolves to `SkillDirDeployAction`) and work without modification because `SkillDirDeployAction` is structurally a superset of the old `DeployAction` — all previously existing fields remain.

